// ===== Birthday & Work Anniversary — find today's matches =====
// Reads the two CSVs fetched by the upstream HTTP nodes, figures out who has a
// birthday / work anniversary TODAY (in AEST), and emits one item per email.

const TIMEZONE = 'Australia/Brisbane'; // UTC+10 year-round, matches 7am AEST

const MONTHS = {jan:1,feb:2,mar:3,apr:4,may:5,jun:6,jul:7,aug:8,sep:9,oct:10,nov:11,dec:12};
const MONTH_NAMES = ['January','February','March','April','May','June','July',
                     'August','September','October','November','December'];

function ordinal(n) {
  if (n % 100 >= 11 && n % 100 <= 13) return n + 'th';
  return n + ({1:'st', 2:'nd', 3:'rd'}[n % 10] || 'th');
}

// Simple CSV parser (no quoted commas in this data)
function parseCsv(text) {
  const lines = String(text).replace(/\r\n/g, '\n').split('\n').filter(l => l.trim() !== '');
  if (!lines.length) return [];
  const headers = lines[0].split(',').map(h => h.trim());
  return lines.slice(1).map(line => {
    const cells = line.split(',');
    const row = {};
    headers.forEach((h, i) => { row[h] = (cells[i] || '').trim(); });
    return row;
  });
}

// "Today" in the target timezone (en-CA gives YYYY-MM-DD parts)
const parts = new Intl.DateTimeFormat('en-CA', {
  timeZone: TIMEZONE, year: 'numeric', month: '2-digit', day: '2-digit'
}).formatToParts(new Date());
const today = {
  year:  Number(parts.find(p => p.type === 'year').value),
  month: Number(parts.find(p => p.type === 'month').value),
  day:   Number(parts.find(p => p.type === 'day').value),
};

// Pull the raw CSV text from the upstream HTTP Request nodes
const employees  = parseCsv($('Get Employees CSV').first().json.data);
const recipients = parseCsv($('Get Recipients CSV').first().json.data)
  .map(r => r.Email)
  .filter(Boolean)
  .join(',');

const out = [];

for (const row of employees) {
  const name = (row.Name || '').trim();
  if (!name) continue;

  const country    = (row.Country || '').trim();
  const department = (row.Department || '').trim();
  const detailLines = [];
  if (country)    detailLines.push('Location: ' + country);
  if (department) detailLines.push('Department: ' + department);
  const details = detailLines.join('\n');

  // --- Birthday: "DD-Mon" (the header has a trailing space in the CSV) ---
  const bday = (row['Birthday '] || row.Birthday || '').trim();
  if (bday) {
    const bits = bday.split('-');
    const bDay = Number(bits[0]);
    const bMonth = MONTHS[(bits[1] || '').toLowerCase()];
    if (bMonth && bDay === today.day && bMonth === today.month) {
      let body = 'Hi,\n\nToday is ' + name + "'s birthday!\n\n";
      body += 'Birthday: ' + String(bDay).padStart(2, '0') + ' ' + MONTH_NAMES[bMonth - 1] + '\n';
      if (details) body += details + '\n';
      body += "\nDon't forget to wish them a happy birthday!\n\n-- Birthday Notifier";
      out.push({ json: { subject: '\u{1F382} Birthday Today: ' + name, body, to: recipients } });
    }
  }

  // --- Work anniversary: Start Date "DD/MM/YYYY" ---
  const start = (row['Start Date'] || '').trim();
  if (start) {
    const bits = start.split('/');
    const sDay = Number(bits[0]), sMonth = Number(bits[1]), sYear = Number(bits[2]);
    if (sDay && sMonth && sYear && sDay === today.day && sMonth === today.month) {
      const years = today.year - sYear;
      if (years > 0) {
        let body = 'Hi,\n\nToday marks ' + name + "'s " + ordinal(years) + ' work anniversary!\n\n';
        body += 'Start date: ' + String(sDay).padStart(2, '0') + ' ' + MONTH_NAMES[sMonth - 1] + ' ' + sYear + '\n';
        body += 'Years with the company: ' + years + '\n';
        if (details) body += details + '\n';
        body += '\nTake a moment to recognise their dedication!\n\n-- Birthday Notifier';
        out.push({ json: { subject: '\u{1F389} Work Anniversary Today: ' + name + ' — ' + ordinal(years) + ' Year!', body, to: recipients } });
      }
    }
  }
}

return out;
